# ============================================================
# VaultLegacy - Wire Final 3 Screens
# ============================================================
# HOW TO RUN:
#   1. Open PowerShell
#   2. cd "C:\Users\HP\Desktop\VaultLegacy"
#   3. .\wire_final.ps1
# ============================================================

$root = Split-Path -Parent $MyInvocation.MyCommand.Path
$FE = Join-Path $root "frontend"
$BE = Join-Path $root "backend"

Write-Host ""
Write-Host "VaultLegacy - Wiring final 3 screens + GitHub security" -ForegroundColor Cyan
Write-Host ""

if (-not (Test-Path $FE)) {
    Write-Host "ERROR: Cannot find frontend folder at: $FE" -ForegroundColor Red
    Write-Host "Make sure this script is inside your VaultLegacy folder." -ForegroundColor Red
    Read-Host "Press Enter to exit"
    exit 1
}
if (-not (Test-Path $BE)) {
    Write-Host "ERROR: Cannot find backend folder at: $BE" -ForegroundColor Red
    Write-Host "Make sure this script is inside your VaultLegacy folder." -ForegroundColor Red
    Read-Host "Press Enter to exit"
    exit 1
}

Write-Host "[1/6] AppealScreen.tsx - wiring to real appeal API..." -ForegroundColor Yellow
$appeal = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\AppealScreen.tsx", $appeal, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[2/6] SignTransferScreen.tsx - wiring to real signing token API..." -ForegroundColor Yellow
$sign = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\SignTransferScreen.tsx", $sign, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[3/6] VaultCertificateScreen.tsx - wiring to real vault data..." -ForegroundColor Yellow
$cert = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$FE\src\screens\VaultCertificateScreen.tsx", $cert, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[4/6] Creating frontend/.gitignore..." -ForegroundColor Yellow
$fegi = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String("bm9kZV9tb2R1bGVzLwpkaXN0LwouZW52Ci5lbnYubG9jYWwKLmVudi5wcm9kdWN0aW9uCioubG9nCg=="))
[System.IO.File]::WriteAllText("$FE\.gitignore", $fegi, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[5/6] Creating backend/.gitignore..." -ForegroundColor Yellow
$begi = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String("bm9kZV9tb2R1bGVzLwpkaXN0LwouZW52CmRhdGEvCnVwbG9hZHMvCioubG9nCg=="))
[System.IO.File]::WriteAllText("$BE\.gitignore", $begi, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host "[6/6] Creating backend/.env.example..." -ForegroundColor Yellow
$envt = [System.Text.Encoding]::UTF8.GetString([System.Convert]::FromBase64String(""))
[System.IO.File]::WriteAllText("$BE\.env.example", $envt, [System.Text.UTF8Encoding]::new($false))
Write-Host "      Done" -ForegroundColor Green

Write-Host ""
Write-Host "============================================" -ForegroundColor Green
Write-Host " All done. Zero mock data remains." -ForegroundColor Green
Write-Host "============================================" -ForegroundColor Green
Write-Host ""
Write-Host "Screens now using real data:" -ForegroundColor White
Write-Host "  AppealScreen            real beneficiary appeal API" -ForegroundColor Gray
Write-Host "  SignTransferScreen      real signing link from executor email" -ForegroundColor Gray
Write-Host "  VaultCertificateScreen  real vault from database + Print/PDF" -ForegroundColor Gray
Write-Host ""
Write-Host "Security files created:" -ForegroundColor White
Write-Host "  frontend/.gitignore  blocks node_modules dist .env" -ForegroundColor Gray
Write-Host "  backend/.gitignore   blocks node_modules dist .env data uploads" -ForegroundColor Gray
Write-Host "  backend/.env.example safe template for Casper to set up locally" -ForegroundColor Gray
Write-Host ""
Write-Host "BEFORE PUSHING TO GITHUB:" -ForegroundColor Yellow
Write-Host "  Run git status inside VaultLegacy" -ForegroundColor Yellow
Write-Host "  Confirm .env and data/ are NOT listed" -ForegroundColor Yellow
Write-Host "  Then: git add .  then  git commit -m wire-final-screens  then  git push" -ForegroundColor Yellow
Write-Host ""
Read-Host "Press Enter to close"
